package com.example.cms.data;
import com.example.cms.common.response.ApiResponse;import com.example.cms.data.audit.*;import com.example.cms.data.backup.*;import com.example.cms.data.migration.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/data") public class DataManagementController{private final AuditLogQueryService audits;private final BackupService backups;private final RestoreConsistencyService restore;private final MigrationService migrations; public DataManagementController(AuditLogQueryService a,BackupService b,RestoreConsistencyService r,MigrationService m){audits=a;backups=b;restore=r;migrations=m;} @GetMapping("/audit-logs") ApiResponse<List<Map<String,Object>>> audits(){return ApiResponse.ok("감사 이력",audits.list());} @PostMapping("/backups") ApiResponse<Map<String,Object>> backup(){return ApiResponse.ok("백업 실행",backups.run());} @GetMapping("/backups") ApiResponse<List<Map<String,Object>>> backups(){return ApiResponse.ok("백업 목록",backups.list());} @PostMapping("/restores") ApiResponse<Map<String,Object>> restore(){return ApiResponse.ok("복구 검증",restore.verify());} @PostMapping("/migrations") ApiResponse<Map<String,Object>> migrate(){return ApiResponse.ok("이관 실행",migrations.run());} @GetMapping("/migrations") ApiResponse<List<Map<String,Object>>> migrations(){return ApiResponse.ok("이관 목록",migrations.list());}}
